# ==============================================================================
# k8s-loadbalancer.conf
# Cau hinh Nginx Load Balancer cho cum Kubernetes
# Phan phoi traffic den cac node qua Ingress Nginx NodePort (30080)
#
# Cach su dung:
#   1. Cai dat Nginx
#      sudo apt install nginx -y
#
#   2. Doi port mac dinh de tranh xung dot port 80
#      sudo vi /etc/nginx/sites-available/default
#      => Sua "listen 80" thanh "listen 9999" (hoac port khac muon dung)
#
#   3. Tao file config voi ten domain cua ban
#      sudo vi /etc/nginx/conf.d/h1eudayne.tech.conf
#      => Sua "h1eudayne.tech" thanh domain ban muon su dung
#      => Copy noi dung file nay vao
#
#   4. Kiem tra va restart Nginx
#      sudo nginx -t
#      sudo systemctl restart nginx
#      sudo systemctl status nginx
# ==============================================================================

# Danh sach cac node Kubernetes
# Port 30080 la NodePort cua Ingress Nginx (cau hinh trong ingress-nginx values.yaml)
upstream my_servers {
    server 192.168.1.111:30080;
    server 192.168.1.112:30080;
    server 192.168.1.113:30080;
}

server {
    listen 80;

    location / {
        proxy_pass http://my_servers;
        proxy_redirect off;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

on-premise/nginx/jenkins-subdomain.conf..content:
# apt install nginx -y
# cd /etc/nginx
# vi conf.d/jenkins.nameURL.tech.conf

# Luu y:
# - Khong them dau "/" o cuoi proxy_pass.
# - Neu Nginx va Jenkins cung may, nen doi upstream thanh 127.0.0.1:8080.
# - Neu dung domain public that, nen them TLS va redirect 80 -> 443.
# - Sau khi xong thi restart nginx: systemctl restart nginx
upstream jenkins {
    keepalive 32;
    server jenkins.h1eudayne.tech:8080;
}

map $http_upgrade $connection_upgrade {
    default upgrade;
    '' close;
}

server {
    listen 80;
    server_name jenkins.elroydevops.tech;

    location / {
        proxy_pass http://jenkins;
        proxy_redirect default;
        proxy_http_version 1.1;

        proxy_set_header Connection        $connection_upgrade;
        proxy_set_header Upgrade           $http_upgrade;

        proxy_set_header Host              $http_host;
        proxy_set_header X-Real-IP         $remote_addr;
        proxy_set_header X-Forwarded-For   $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        proxy_read_timeout 90;
        proxy_connect_timeout 90;
        proxy_send_timeout 90;
        proxy_request_buffering off;
        proxy_max_temp_file_size 0;

        client_max_body_size 10m;
        client_body_buffer_size 128k;
    }
}

