-- --------------------------------------------------------
-- SQL Template for AWS RDS Hands-on Lab
-- Description: Basic CRUD operations and Slow Query simulation
-- --------------------------------------------------------

-- 1. Create and use database
CREATE DATABASE IF NOT EXISTS company;
USE company;

-- 2. Create employees table
CREATE TABLE IF NOT EXISTS employees (
    id INT NOT NULL PRIMARY KEY AUTO_INCREMENT,
    name VARCHAR(100) NOT NULL,
    address VARCHAR(255) NOT NULL,
    salary INT(10) NOT NULL
);

-- 3. Insert sample data (Create)
INSERT INTO employees (name, address, salary) VALUES
('Linh', 'Quan 12, TPHCM', 5000000),
('Chien', 'Quan 1, TPHCM', 1000000),
('Thong', 'Quan 9, TPHCM', 20000000),
('Hai Huy', 'Quan 13, TPHCM', 5000000);

-- 4. Retrieve data (Read)
SELECT * FROM employees;

-- 5. Update data (Update)
UPDATE employees SET salary = 30000000 WHERE id = 3;

-- 6. Delete data (Delete)
DELETE FROM employees WHERE id = 2;

-- 7. Query to verify changes
SELECT * FROM employees;

-- --------------------------------------------------------
-- 8. Simulate Slow Query using Custom Function
-- --------------------------------------------------------
DELIMITER $$
DROP FUNCTION IF EXISTS `iterateSleep` $$
CREATE FUNCTION `iterateSleep` (iterations INT)
RETURNS INT DETERMINISTIC
BEGIN
    DECLARE remainder INT;

    SET remainder = iterations;

    read_loop: LOOP     
        IF remainder = 0 THEN
            LEAVE read_loop;
        END IF;

        SELECT SLEEP(2) INTO @test;
        SET remainder = remainder - 1;          
    END LOOP;

    RETURN iterations;
END $$
DELIMITER ;

-- Test out the slow query function (simulates a query taking ~4 seconds)
SELECT iterateSleep(2);

pipelines/jenkins/continuous-delivery/ja.content:
pipeline {
    agent {
        label 'lab-server'
    }
    environment {
        appUser = "shoeshop"
        appName = "shoe-ShoppingCart"
        appVersion = "0.0.1-SNAPSHOT"
        appType = "jar"
        processName = "${appName}-${appVersion}.${appType}"
        folderDeploy = "/datas/${appUser}"
        buildScript = "mvn clean install -DskipTests=true"
        copyScript = "sudo cp target/${processName} ${folderDeploy}"
        permsScript = "sudo chown -R ${appUser}. ${folderDeploy}"
        killScript = "pids=\$(ps -ef | grep ${processName} | grep -v grep | awk '{print \$2}'); [ -n \"\$pids\" ] && sudo kill -9 \$pids || true"
        runScript = "sudo su ${appUser} -c \"cd ${folderDeploy}; java -jar ${processName} > nohup.out 2>&1 &\""
    }
    stages {
        stage('build') {
            steps {
                sh(script: """ ${buildScript} """, label: "build with maven")
            }
        }
        stage('deploy') {
            steps {
                script {
                    try {
                        def deployChoice = timeout(time: 5, unit: 'MINUTES') {
                            input(
                                message: "Can it be deployed?",
                                parameters: [
                                    choice(
                                        name: 'deploy',
                                        choices: 'Yes\nNo',
                                        description: 'Choose "Yes" if you want to deploy'
                                    )
                                ]
                            )
                        }

                        if (deployChoice == 'Yes') {
                            sh(script: """ ${copyScript} """, label: "copy the .jar file into deploy folder")
                            sh(script: """ ${permsScript} """, label: "set permission folder")
                            sh(script: """ ${killScript} """, label: "terminate the running process")
                            sh(script: """ ${runScript} """, label: "run the project")
                        } else {
                            echo "Deployment was not confirmed."
                        }
                    } catch (Exception err) {
                        echo "Deployment was skipped because approval was not completed."
                    }
                }
            }
        }
    }
}

properties([
    parameters([
        choice(
            name: 'action',
            choices: 'start\nstop\nupcode\nrollback',
            description: 'Choose the delivery action to run'
        ),
        string(
            name: 'server',
            defaultValue: 'lab-server',
            description: 'Jenkins node name used to run this job'
        ),
        string(
            name: 'hash',
            defaultValue: '',
            description: 'Git branch, tag, or commit used for the upcode action'
        ),
        string(
            name: 'rollback_version',
            defaultValue: '',
            description: 'Backup zip file used for the rollback action'
        )
    ])
])

appUser = "shoeshop"
appName = "shoe-ShoppingCart"
appVersion = "0.0.1-SNAPSHOT"
appType = "jar"
processName = "${appName}-${appVersion}.${appType}"
folderDeploy = "/datas/${appUser}/run"
folderBackup = "/datas/${appUser}/backups"
folderMain = "/datas/${appUser}"
buildScript = "mvn clean install -DskipTests=true"
copyScript = "sudo cp target/${processName} ${folderDeploy}"
permsScript = "sudo chown -R ${appUser}. ${folderDeploy}"
killScript = "pids=\$(ps -ef | grep ${processName} | grep -v grep | awk '{print \$2}'); [ -n \"\$pids\" ] && sudo kill -9 \$pids || true"
runScript = "sudo su ${appUser} -c 'cd ${folderDeploy}; java -jar ${processName} > nohup.out 2>&1 &'"
gitLink = "http://git.h1eudayne.tech/shoeshop/shoeshop.git"

def getProcessId(processName) {
    return sh(
        returnStdout: true,
        script: """ps -ef | grep ${processName} | grep -v grep | awk '{print \$2}'""",
        label: "get process id"
    ).trim()
}

def startProcess() {
    stage('start') {
        sh(script: """ ${runScript} """, label: "run the project")
        sleep 5
        def processId = getProcessId("${processName}")
        if (processId == "") {
            error("Cannot start process")
        }
    }
    echo("${appName} with server ${params.server} started")
}

def stopProcess() {
    stage('stop') {
        def processId = getProcessId("${processName}")
        if (processId != "") {
            sh(script: """ ${killScript} """, label: "kill process")
        }
        echo("${appName} with server ${params.server} stopped")
    }
}

def upcodeProcess() {
    stage('checkout') {
        if (params.hash.trim() == "") {
            error("Require a Git hash, branch, or tag for code update.")
        }
        checkout([
            $class: 'GitSCM',
            branches: [[name: params.hash.trim()]],
            userRemoteConfigs: [[
                credentialsId: 'jenkins-gitlab-user-account',
                url: gitLink
            ]]
        ])
    }
    stage('build') {
        sh(script: """ ${buildScript} """, label: "build with maven")
    }
    stage('config') {
        sh(script: """ ${copyScript} """, label: "copy .jar file into the deploy folder")
        sh(script: """ ${permsScript} """, label: "assign project permissions")
    }
}

def backupProcess() {
    stage('backup') {
        def timeStamp = new Date().format("ddMMyyyy_HHmm")
        def zipFileName = "${appName}_${timeStamp}.zip"
        sh(
            script: """ sudo su ${appUser} -c "cd ${folderMain}; zip -jr ${folderBackup}/${zipFileName} ${folderDeploy}" """,
            label: "backup old version"
        )
    }
}

def rollbackProcess() {
    stage('rollback') {
        if (params.rollback_version.trim() == "") {
            error("Require a backup zip file for rollback.")
        }
        sh(
            script: """ sudo su ${appUser} -c "cd ${folderDeploy}; rm -rf *" """,
            label: "delete the current version"
        )
        sh(
            script: """ sudo su ${appUser} -c "cd ${folderBackup}; unzip ${params.rollback_version.trim()} -d ${folderDeploy}" """,
            label: "rollback process"
        )
    }
}

node(params.server) {
    currentBuild.displayName = params.action

    switch (params.action) {
        case "start":
            startProcess()
            break
        case "stop":
            stopProcess()
            break
        case "upcode":
            currentBuild.description = "server ${params.server} with hash ${params.hash}"
            backupProcess()
            stopProcess()
            upcodeProcess()
            startProcess()
            break
        case "rollback":
            currentBuild.description = "server ${params.server} with rollback ${params.rollback_version}"
            stopProcess()
            rollbackProcess()
            startProcess()
            break
        default:
            error("Unsupported action: ${params.action}")
    }
}

import jenkins.model.Jenkins
import hudson.FilePath

def backupPath = "/datas/shoeshop/backups"

if (action != 'rollback') {
    return ['Not used for this action:selected']
}

if (!server?.trim()) {
    return ['Select server first:selected']
}

def node = Jenkins.get().getNode(server.trim())
if (node == null) {
    return ["Node not found: ${server}"]
}

def channel = node.getChannel()
if (channel == null) {
    return ["Node offline: ${server}"]
}

def remoteDir = new FilePath(channel, backupPath)
if (!remoteDir.exists()) {
    return ["Backup folder not found: ${backupPath}"]
}

def backups = remoteDir.list("*.zip")
    .findAll { !it.isDirectory() }
    .sort { a, b -> b.lastModified() <=> a.lastModified() }
    .collect { it.name }

return backups ?: ['No backup files found']

